```aether:src/db.ts
import { Task } from './types';

// In-memory database simulation
const tasks: Task[] = [
  {
    id: 'task-1',
    title: 'Buy groceries',
    description: 'Milk, eggs, bread, butter',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
  {
    id: 'task-2',
    title: 'Finish project report',
    description: 'Complete the Q3 financial report',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
  {
    id: 'task-3',
    title: 'Call mom',
    description: 'Wish her a happy birthday',
    createdAt: new Date(),
    updatedAt: new Date(),
  },
];

export const getTasks = (): Task[] => {
  // Return only non-deleted tasks for a typical "list all" scenario
  return tasks.filter(task => !task.deletedAt);
};

export const getTaskById = (id: string): Task | undefined => {
  return tasks.find(task => task.id === id);
};

export const softDeleteTask = (id: string): Task | undefined => {
  const taskIndex = tasks.findIndex(task => task.id === id);
  if (taskIndex === -1) {
    return undefined;
  }

  // Ensure we don't re-delete an already deleted task, or update its deletedAt if already set
  if (tasks[taskIndex].deletedAt) {
    return tasks[taskIndex]; // Already soft-deleted, return as is
  }

  tasks[taskIndex] = {
    ...tasks[taskIndex],
    deletedAt: new Date(),
    updatedAt: new Date(), // Also update updatedAt when soft-deleting
  };
  return tasks[taskIndex];
};

// For demonstration purposes, a way to add tasks
export const addTask = (title: string, description?: string): Task => {
  const newTask: Task = {
    id: `task-${tasks.length + 1}`,
    title,
    description,
    createdAt: new Date(),
    updatedAt: new Date(),
  };
  tasks.push(newTask);
  return newTask;
};
```

```aether:src/routes/tasks.ts
import { Hono } from 'hono';
import { getTasks, getTaskById, softDeleteTask } from '../db';

const tasksRouter = new Hono();

// GET /tasks - List all non-deleted tasks
tasksRouter.get('/', (c) => {
  const tasks = getTasks();
  return c.json(tasks);
});

// GET /tasks/:id - Get a single task (including potentially deleted ones for admin views, or just non-deleted)
// For this exercise, we'll allow fetching by ID even if deleted, but the main list filters them out.
tasksRouter.get('/:id', (c) => {
  const { id } = c.req.param();
  const task = getTaskById(id);

  if (!task) {
    return c.json({ message: 'Task not found' }, 404);
  }
  return c.json(task);
});

// DELETE /tasks/:id - Soft-delete a task
tasksRouter.delete('/:id', (c) => {
  const { id } = c.req.param();
  const updatedTask = softDeleteTask(id);

  if (!updatedTask) {
    return c.json({ message: 'Task not found' }, 404);
  }

  if (updatedTask.deletedAt) {
    return c.json({ message: 'Task soft-deleted successfully', task: updatedTask }, 200);
  } else {
    // This case should ideally not be hit if softDeleteTask correctly sets deletedAt
    return c.json({ message: 'Failed to soft-delete task' }, 500);
  }
});

export default tasksRouter;
```

```aether:src/index.ts
import { Hono } from 'hono';
import tasksRouter from './routes/tasks';

const app = new Hono();

// Basic logging middleware
app.use('*', async (c, next) => {
  console.log(`[${c.req.method}] ${c.req.url}`);
  await next();
});

// Register task routes
app.route('/tasks', tasksRouter);

// Root route
app.get('/', (c) => {
  return c.text('Welcome to the Task API! Try /tasks');
});

// Global error handler
app.onError((err, c) => {
  console.error(`${err}`);
  return c.json({ message: 'An internal server error occurred' }, 500);
});

// Export the Hono app for serverless environments or direct Node.js execution
export default app;

// To run with Node.js (e.g., using `node src/index.ts` with a runner like `tsx` or `ts-node`)
// This part is for local development and demonstration.
if (process.env.NODE_ENV !== 'test') {
  const port = process.env.PORT ? parseInt(process.env.PORT) : 3000;
  console.log(`Server is running on http://localhost:${port}`);
  // Hono's app.fetch is compatible with Node.js http server
  // For a full Node.js server, you'd typically use something like:
  // import { serve } from '@hono/node-server';
  // serve({ fetch: app.fetch, port });
  // For this exercise, we'll keep it minimal and assume a runtime that can handle `app.fetch`.
  // If you were to run this directly with `node`, you'd need `@hono/node-server`.
  // For example, in a separate file `server.ts`:
  // import { serve } from '@hono/node-server';
  // import app from './index';
  // serve({ fetch: app.fetch, port: 3000 });
}
